class Solution:
    def minOperations(self, s1: str, s2: str, x: int) -> int:
        n = len(s1)
        diff = []
        for i in range(n):
            if s1[i] != s2[i]:
                diff.append(i)

        if len(diff) % 2 != 0:
            return -1

        m = len(diff)
        dp = [float('inf')] * (m + 1)
        dp[0] = 0

        for i in range(1, m + 1):
            for j in range(i - 1, -1, -2):
                cost = (diff[i - 1] - diff[j]) * x
                dp[i] = min(dp[i], dp[j] + cost)

        return dp[m] if dp[m] != float('inf') else -1
